15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	
19	library surf;
20	use surf.StdRtlPkg.all;
21	use surf.AxiStreamPkg.all;
22	
23	entity AxiStreamPipeline is
24	   generic (
25	      TPD_G             : time     := 1 ns;
26	      RST_POLARITY_G    : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
27	      RST_ASYNC_G       : boolean  := false;
28	      SIDE_BAND_WIDTH_G : positive := 1;    -- General purpose sideband
29	      PIPE_STAGES_G     : natural  := 0);
30	   port (
31	      -- Clock and Reset
32	      axisClk     : in  sl;
33	      axisRst     : in  sl;
34	      -- Slave Port
35	      sAxisMaster : in  AxiStreamMasterType;
36	      sSideBand   : in  slv(SIDE_BAND_WIDTH_G-1 downto 0) := (others => '0');
37	      sAxisSlave  : out AxiStreamSlaveType;
38	      -- Master Port
39	      mAxisMaster : out AxiStreamMasterType;
40	      mSideBand   : out slv(SIDE_BAND_WIDTH_G-1 downto 0);
41	      mAxisSlave  : in  AxiStreamSlaveType);
42	end AxiStreamPipeline;
43	
44	architecture rtl of AxiStreamPipeline is
45	
46	   constant PIPE_STAGES_C : natural := PIPE_STAGES_G+1;
47	
48	   type SideBandArray is array (natural range <>) of slv(SIDE_BAND_WIDTH_G-1 downto 0);
49	
50	   type RegType is record
51	      sAxisSlave  : AxiStreamSlaveType;
52	      mAxisMaster : AxiStreamMasterArray(0 to PIPE_STAGES_C);
53	      mSideBand   : SideBandArray(0 to PIPE_STAGES_C);
54	   end record RegType;
55	
56	   constant REG_INIT_C : RegType := (
57	      sAxisSlave  => AXI_STREAM_SLAVE_INIT_C,
58	      mAxisMaster => (others => AXI_STREAM_MASTER_INIT_C),
59	      mSideBand   => (others => (others => '0')));
60	
61	   signal r   : RegType := REG_INIT_C;
62	   signal rin : RegType;
63	
64	begin
65	
66	   ZERO_LATENCY : if (PIPE_STAGES_G = 0) generate
67	
68	      mAxisMaster <= sAxisMaster;
69	      mSideBand   <= sSideBand;
70	      sAxisSlave  <= mAxisSlave;
71	
72	   end generate;
73	
74	   PIPE_REG : if (PIPE_STAGES_G > 0) generate
75	
76	      comb : process (axisRst, mAxisSlave, r, sAxisMaster, sSideBand) is
77	         variable v : RegType;
78	      begin
79	         -- Latch the current value
80	         v := r;
81	
82	         -- Check if we need to shift register
83	         if (r.mAxisMaster(PIPE_STAGES_C).tValid = '0') or (mAxisSlave.tReady = '1') then
84	            -- Shift the data up the pipeline
85	            for i in PIPE_STAGES_C downto 2 loop
86	               v.mAxisMaster(i) := r.mAxisMaster(i-1);
87	               v.mSideBand(i)   := r.mSideBand(i-1);
88	            end loop;
89	            -- Check if the lowest cell is empty
90	            if r.mAxisMaster(0).tValid = '0' then
91	               -- Set the ready bit
92	               v.sAxisSlave.tReady := '1';
93	               -- Check if we were pulling the FIFO last clock cycle
94	               if r.sAxisSlave.tReady = '1' then
95	                  -- Shift the FIFO data
96	                  v.mAxisMaster(1) := sAxisMaster;
97	                  v.mSideBand(1)   := sSideBand;
98	               else
99	                  -- Clear valid in stage 1
100	                  v.mAxisMaster(1).tValid := '0';
101	               end if;
102	            else
103	               -- Shift the lowest cell
104	               v.mAxisMaster(1) := r.mAxisMaster(0);
105	               v.mSideBand(1)   := r.mSideBand(0);
106	               -- Check if we were pulling the FIFO last clock cycle
107	               if r.sAxisSlave.tReady = '1' then
108	                  -- Reset the ready bit
109	                  v.sAxisSlave.tReady := '0';
110	                  -- Fill the lowest cell
111	                  v.mAxisMaster(0)    := sAxisMaster;
112	                  v.mSideBand(0)      := sSideBand;
113	               else
114	                  -- Set the ready bit
115	                  v.sAxisSlave.tReady     := '1';
116	                  -- Reset the lowest cell tValid
117	                  v.mAxisMaster(0).tValid := '0';
118	               end if;
119	            end if;
120	         else
121	            -- Reset the ready bit
122	            v.sAxisSlave.tReady := '0';
123	            -- Check if we were pulling the FIFO last clock cycle
124	            if r.sAxisSlave.tReady = '1' then
125	               -- Fill the lowest cell
126	               v.mAxisMaster(0) := sAxisMaster;
127	               v.mSideBand(0)   := sSideBand;
128	            elsif r.mAxisMaster(0).tValid = '0' then
129	               -- Set the ready bit
130	               v.sAxisSlave.tReady := '1';
131	            end if;
132	            -- Check if we need to internally shift the data to remove gaps
133	            for i in PIPE_STAGES_C-1 downto 1 loop
134	               -- Check for empty cell ahead of a filled cell
135	               if (r.mAxisMaster(i).tValid = '0') and (r.mAxisMaster(i-1).tValid = '1') then
136	                  -- Shift the lowest cell
137	                  v.mAxisMaster(i)          := r.mAxisMaster(i-1);
138	                  v.mSideBand(i)            := r.mSideBand(i-1);
139	                  -- Reset the flag
140	                  v.mAxisMaster(i-1).tValid := '0';
141	               end if;
142	            end loop;
143	         end if;
144	
145	         -- Outputs
146	         sAxisSlave  <= r.sAxisSlave;
147	         mAxisMaster <= r.mAxisMaster(PIPE_STAGES_C);
148	         mSideBand   <= r.mSideBand(PIPE_STAGES_C);
149	
150	         -- Synchronous Reset
151	         if (RST_ASYNC_G = false and axisRst = RST_POLARITY_G) then
152	            v := REG_INIT_C;
153	         end if;
154	
155	         -- Register the variable for next clock cycle
156	         rin <= v;
157	
158	      end process comb;
159	
160	      seq : process (axisClk, axisRst) is
161	      begin
162	         if (RST_ASYNC_G and axisRst = RST_POLARITY_G) then
163	            r <= REG_INIT_C after TPD_G;
164	         elsif rising_edge(axisClk) then
165	            r <= rin after TPD_G;
166	         end if;
167	      end process seq;
168	
169	   end generate;
170	
171	end rtl;
