8	-- top-level directory of this distribution and at:
9	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
10	-- No part of 'SLAC Firmware Standard Library', including this file,
11	-- may be copied, modified, propagated, or distributed except according to
12	-- the terms contained in the LICENSE.txt file.
13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_unsigned.all;
18	use ieee.std_logic_arith.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiPkg.all;                    -- Dependence with AxiPkg due to DMA
23	-- use surf.TextUtilPkg.all;
24	
25	package AxiStreamPkg is
26	
27	   constant AXI_STREAM_MAX_TDATA_WIDTH_C : positive := AXI_MAX_DATA_WIDTH_C;  -- Units of bits
28	   constant AXI_STREAM_MAX_TKEEP_WIDTH_C : positive := AXI_MAX_WSTRB_WIDTH_C;  -- Units of bytes
29	
30	   type AxiStreamMasterType is record
31	      tValid : sl;
32	      tData  : slv(AXI_STREAM_MAX_TDATA_WIDTH_C-1 downto 0);
33	      tStrb  : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
34	      tKeep  : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
35	      tLast  : sl;
36	      tDest  : slv(7 downto 0);
37	      tId    : slv(7 downto 0);
38	      tUser  : slv(AXI_STREAM_MAX_TDATA_WIDTH_C-1 downto 0);
39	   end record AxiStreamMasterType;
40	
41	   constant AXI_STREAM_MASTER_INIT_C : AxiStreamMasterType := (
42	      tValid => '0',
43	      tData  => (others => '0'),
44	      tStrb  => (others => '1'),
45	      tKeep  => (others => '1'),
46	      tLast  => '0',
47	      tDest  => (others => '0'),
48	      tId    => (others => '0'),
49	      tUser  => (others => '0'));
50	   type AxiStreamMasterArray is array (natural range<>) of AxiStreamMasterType;
51	   type AxiStreamMasterVectorArray is array (natural range<>, natural range<>) of AxiStreamMasterType;
52	   subtype AxiStreamDualMasterType is AxiStreamMasterArray(1 downto 0);
53	   type AxiStreamDualMasterArray is array (natural range <>) of AxiStreamMasterArray(1 downto 0);
54	   subtype AxiStreamQuadMasterType is AxiStreamMasterArray(3 downto 0);
55	   type AxiStreamQuadMasterArray is array (natural range <>) of AxiStreamMasterArray(3 downto 0);
56	   subtype AxiStreamOctalMasterType is AxiStreamMasterArray(7 downto 0);
57	   type AxiStreamOctalMasterArray is array (natural range <>) of AxiStreamMasterArray(7 downto 0);
58	
59	   type AxiStreamSlaveType is record
60	      tReady : sl;
61	   end record AxiStreamSlaveType;
62	
63	   type AxiStreamSlaveArray is array (natural range<>) of AxiStreamSlaveType;
64	   type AxiStreamSlaveVectorArray is array (natural range<>, natural range<>) of AxiStreamSlaveType;
65	   subtype AxiStreamDualSlaveType is AxiStreamSlaveArray(1 downto 0);
66	   type AxiStreamDualSlaveArray is array (natural range <>) of AxiStreamSlaveArray(1 downto 0);
67	   subtype AxiStreamQuadSlaveType is AxiStreamSlaveArray(3 downto 0);
68	   type AxiStreamQuadSlaveArray is array (natural range <>) of AxiStreamSlaveArray(3 downto 0);
69	   subtype AxiStreamOctalSlaveType is AxiStreamSlaveArray(7 downto 0);
70	   type AxiStreamOctalSlaveArray is array (natural range <>) of AxiStreamSlaveArray(7 downto 0);
71	
72	   constant AXI_STREAM_SLAVE_INIT_C : AxiStreamSlaveType := (
73	      tReady => '0');
74	
75	   constant AXI_STREAM_SLAVE_FORCE_C : AxiStreamSlaveType := (
76	      tReady => '1');
77	
78	   type TUserModeType is (TUSER_NORMAL_C, TUSER_FIRST_LAST_C, TUSER_LAST_C, TUSER_NONE_C);
79	
80	   type TKeepModeType is (TKEEP_NORMAL_C, TKEEP_COMP_C, TKEEP_FIXED_C, TKEEP_COUNT_C);
81	
82	   type AxiStreamConfigType is record
83	      -- TDEST_INTERLEAVE_C : boolean;
84	      TSTRB_EN_C    : boolean;
85	      TDATA_BYTES_C : natural range 1 to AXI_STREAM_MAX_TKEEP_WIDTH_C;
86	      TDEST_BITS_C  : natural range 0 to 8;
87	      TID_BITS_C    : natural range 0 to 8;
88	      TKEEP_MODE_C  : TkeepModeType;
89	      TUSER_BITS_C  : natural range 0 to 8;
90	      TUSER_MODE_C  : TUserModeType;
91	   end record AxiStreamConfigType;
92	
93	   constant AXI_STREAM_CONFIG_INIT_C : AxiStreamConfigType := (
94	      -- TDEST_INTERLEAVE_C => true,
95	      TSTRB_EN_C    => false,
96	      TDATA_BYTES_C => 16,
97	      TDEST_BITS_C  => 4,
98	      TID_BITS_C    => 0,
99	      TKEEP_MODE_C  => TKEEP_NORMAL_C,
100	      TUSER_BITS_C  => 4,
101	      TUSER_MODE_C  => TUSER_NORMAL_C);
102	
103	   type AxiStreamConfigArray is array (natural range<>) of AxiStreamConfigType;
104	   type AxiStreamConfigVectorArray is array (natural range<>, natural range<>) of AxiStreamConfigType;
105	
106	   function axiStreamMasterInit (constant config : AxiStreamConfigType) return AxiStreamMasterType;
107	
108	   function getSlvSize (c          : AxiStreamConfigType) return integer;
109	   function toSlv (din             : AxiStreamMasterType; c : AxiStreamConfigType) return slv;
110	   function toAxiStreamMaster (din : slv; valid : sl; c : AxiStreamConfigType) return AxiStreamMasterType;
111	
112	   -------------------------------------------------------------------------------------------------
113	   -- Special control backpressure interface for use with stream fifos
114	   -------------------------------------------------------------------------------------------------
115	   type AxiStreamCtrlType is record
116	      pause    : sl;
117	      overflow : sl;
118	      idle     : sl;
119	   end record AxiStreamCtrlType;
120	
121	   constant AXI_STREAM_CTRL_INIT_C : AxiStreamCtrlType := (
122	      pause    => '1',
123	      overflow => '0',
124	      idle     => '0');
125	
126	   constant AXI_STREAM_CTRL_UNUSED_C : AxiStreamCtrlType := (
127	      pause    => '0',
128	      overflow => '0',
129	      idle     => '1');
130	
131	   type AxiStreamCtrlArray is array (natural range<>) of AxiStreamCtrlType;
132	   type AxiStreamCtrlVectorArray is array (natural range<>, natural range<>) of AxiStreamCtrlType;
133	   subtype AxiStreamDualCtrlType is AxiStreamCtrlArray(1 downto 0);
134	   type AxiStreamDualCtrlArray is array (natural range <>) of AxiStreamCtrlArray(1 downto 0);
135	   subtype AxiStreamQuadCtrlType is AxiStreamCtrlArray(3 downto 0);
136	   type AxiStreamQuadCtrlArray is array (natural range <>) of AxiStreamCtrlArray(3 downto 0);
137	   subtype AxiStreamOctalCtrlType is AxiStreamCtrlArray(7 downto 0);
138	   type AxiStreamOctalCtrlArray is array (natural range <>) of AxiStreamCtrlArray(7 downto 0);
139	
140	   -------------------------------------------------------------------------------------------------
141	   -- Helper function prototypes
142	   -------------------------------------------------------------------------------------------------
143	   function axiStreamPacked (
144	      constant CONFIG_C : AxiStreamConfigType;
145	      axisMaster        : AxiStreamMasterType)
146	      return boolean;
147	
148	   function axiStreamGetUserPos (
149	      axisConfig : AxiStreamConfigType;
150	      axisMaster : AxiStreamMasterType;
151	      bytePos    : integer := -1)       -- -1 = last
152	      return integer;
153	
154	   function axiStreamGetUserField (
155	      axisConfig : AxiStreamConfigType;
156	      axisMaster : AxiStreamMasterType;
157	      bytePos    : integer := -1)       -- -1 = last
158	      return slv;
159	
160	   function axiStreamGetUserBit (
161	      axisConfig : AxiStreamConfigType;
162	      axisMaster : AxiStreamMasterType;
163	      bitPos     : integer;
164	      bytePos    : integer := -1)       -- -1 = last
165	      return sl;
166	
167	   procedure axiStreamSetUserField (
168	      axisConfig : in    AxiStreamConfigType;
169	      axisMaster : inout AxiStreamMasterType;
170	      fieldValue : in    slv;
171	      bytePos    : in    integer := -1);  -- -1 = last
172	
173	   procedure axiStreamSetUserBit (
174	      axisConfig : in    AxiStreamConfigType;
175	      axisMaster : inout AxiStreamMasterType;
176	      bitPos     : in    integer;
177	      bitValue   : in    sl;
178	      bytePos    : in    integer := -1);  -- -1 = last
179	
180	   function ite(i : boolean; t : AxiStreamConfigType; e : AxiStreamConfigType) return AxiStreamConfigType;
181	   function ite(i : boolean; t : AxiStreamMasterType; e : AxiStreamMasterType) return AxiStreamMasterType;
182	   function ite(i : boolean; t : AxiStreamSlaveType; e : AxiStreamSlaveType) return AxiStreamSlaveType;
