221	   function axiStreamGetUserPos (
222	      axisConfig : AxiStreamConfigType;
223	      axisMaster : AxiStreamMasterType;
224	      bytePos    : integer := -1)
225	      return integer is
226	
227	      variable ret : integer;
228	   begin
229	
230	      if bytePos = -1 then
231	         ret := getTKeep(axisMaster.tKeep, axisConfig)-1;
232	         if (ret > axisConfig.TDATA_BYTES_C) then
233	            ret := axisConfig.TDATA_BYTES_C-1;
234	         end if;
235	         if ret < 0 then
236	            ret := 0;
237	         end if;
238	      else
239	         ret := bytePos;
240	      end if;
241	
242	      return(ret);
243	   end function;
244	
245	   function axiStreamGetUserField (
246	      axisConfig : AxiStreamConfigType;
247	      axisMaster : AxiStreamMasterType;
248	      bytePos    : integer := -1)
249	      return slv is
250	
251	      variable pos : integer;
252	      variable lsb : integer;
253	      variable ret : slv(maximum(axisConfig.TUSER_BITS_C-1, 0) downto 0);
254	   begin
255	
256	      pos := axiStreamGetUserPos(axisConfig, axisMaster, bytePos);
257	      lsb := axisConfig.TUSER_BITS_C*pos;
258	
259	      if axisConfig.TUSER_BITS_C > 0 then
260	         for i in 0 to AXI_STREAM_MAX_TDATA_WIDTH_C-ret'high-ret'low-1 loop
261	            if lsb = i then
262	               ret := axisMaster.tUser(ret'high+i downto ret'low+i);
263	            end if;
264	         end loop;
265	      else
266	         ret := (others => '0');
267	      end if;
268	
269	      -- Handle TUSER_BITS_C=0 case
270	      if (axisConfig.TUSER_BITS_C = 0 or axisConfig.TUSER_MODE_C = TUSER_NONE_C) then
271	         ret := (others => '0');
272	      end if;
273	
274	      return(ret);
275	   end function;
