359	   function genTKeep (bytes : natural range 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C) return slv is
360	      variable retVar : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
361	   begin
362	      retVar := (others => '0');
363	      for i in 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C-1 loop
364	         if (bytes > i) then
365	            retVar(i) := '1';
366	         end if;
367	      end loop;
368	      return retVar;
369	   end function genTKeep;
370	
371	   function genTKeep (bytes : slv) return slv is
372	      variable retVar   : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
373	      variable bytesExt : slv(bitSize(AXI_STREAM_MAX_TKEEP_WIDTH_C)-1 downto 0);
374	   begin
375	      retVar   := (others => '0');
376	      bytesExt := resize(bytes, bytesExt'length);
377	      for i in 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C-1 loop
378	         if (bytesExt >= toSlv(i+1, bytesExt'length)) then
379	            retVar(i) := '1';
380	         end if;
381	      end loop;
382	      return retVar;
383	   end function genTKeep;
